return {
  draw: function(ctx, W, H, t, dt) {
    // Background
    ctx.fillStyle = '#111827';
    ctx.fillRect(0, 0, W, H);

    // Middle separator line
    ctx.strokeStyle = '#374151';
    ctx.lineWidth = 2;
    ctx.beginPath();
    ctx.moveTo(W / 2, 20);
    ctx.lineTo(W / 2, H - 20);
    ctx.stroke();

    // Labels
    ctx.fillStyle = '#F3F4F6';
    ctx.font = 'bold 15px -apple-system, sans-serif';
    ctx.textAlign = 'center';
    ctx.fillText('7 (Prime Number)', W / 4, 35);
    ctx.fillText('8 (Composite Number)', W * 3 / 4, 35);

    // Dot size
    var r = 8;
    var paddingX1 = W / 4;
    var paddingX2 = W * 3 / 4;
    var centerY = H / 2 + 10;

    // Animation timing (6s cycle)
    var duration = 6000;
    var progress = (t % duration) / duration;

    // --- LEFT SIDE: 7 Dots (Prime) ---
    // Try to arrange 7 in a 2-row layout: 3 columns + 1 leftover
    // We'll show the grid, then highlight the leftover flashing red
    var cols1 = 3;
    var dx = 28;
    var dy = 28;

    var startX1 = paddingX1 - ((cols1 - 1) * dx) / 2;
    var startY1 = centerY - dy / 2;

    for (var i = 0; i < 7; i++) {
      var col = i % 3;
      var row = Math.floor(i / 3);
      var px = startX1 + col * dx;
      var py = startY1 + row * dy;

      if (i === 6) {
        // Leftover dot
        var flash = Math.sin(t * 0.015) > 0;
        ctx.fillStyle = flash ? '#EF4444' : '#FBBF24'; // Red flashing warning
        ctx.beginPath();
        ctx.arc(px, py, r + 2, 0, Math.PI * 2);
        ctx.fill();
      } else {
        ctx.fillStyle = '#6B7280'; // Neutral color for matched dots
        ctx.beginPath();
        ctx.arc(px, py, r, 0, Math.PI * 2);
        ctx.fill();
      }
    }

    // Sublabel left
    ctx.fillStyle = '#EF4444';
    ctx.font = '12px -apple-system, sans-serif';
    ctx.fillText('Uneven! Leftover dot.', W / 4, H - 40);
    ctx.fillStyle = '#9CA3AF';
    ctx.fillText('Only 1 x 7 layout works', W / 4, H - 20);


    // --- RIGHT SIDE: 8 Dots (Composite) ---
    // Arrange 8 in a perfect 2 x 4 grid
    var cols2 = 4;
    var rows2 = 2;
    var startX2 = paddingX2 - ((cols2 - 1) * dx) / 2;
    var startY2 = centerY - ((rows2 - 1) * dy) / 2;

    // Draw bounding box
    ctx.strokeStyle = '#10B981';
    ctx.lineWidth = 1.5;
    ctx.beginPath();
    ctx.roundRect(startX2 - r - 8, startY2 - r - 8, (cols2 - 1) * dx + r * 2 + 16, (rows2 - 1) * dy + r * 2 + 16, 6);
    ctx.stroke();

    for (var j = 0; j < 8; j++) {
      var col2 = j % 4;
      var row2 = Math.floor(j / 4);
      var px2 = startX2 + col2 * dx;
      var py2 = startY2 + row2 * dy;

      ctx.fillStyle = '#34D399'; // Neat green dots
      ctx.beginPath();
      ctx.arc(px2, py2, r, 0, Math.PI * 2);
      ctx.fill();
    }

    // Sublabel right
    ctx.fillStyle = '#34D399';
    ctx.font = 'bold 13px -apple-system, sans-serif';
    ctx.fillText('Perfect 2 x 4 rectangle!', W * 3 / 4, H - 40);
    ctx.fillStyle = '#9CA3AF';
    ctx.font = '12px -apple-system, sans-serif';
    ctx.fillText('Multiple layouts: 1x8, 2x4', W * 3 / 4, H - 20);
  }
};
